  ('dietitian-moex-00923', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '雇主依勞動基準法第16條終止勞動契約者，其預告期間之規定，下列何者錯誤？', '["繼續工作未滿3個月者，於5日前預告之", "繼續工作3個月以上1年未滿者，於10日前預告之", "繼續工作1年以上3年未滿者，於20日前預告之", "繼續工作3年以上者，於30日前預告之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00924', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某餐廳準備100人份彩椒雞丁，購買紅甜椒500元、黃甜椒400元、香菇200元、雞丁2,500元、 便當盒200元、瓦斯150元，當每份售價以80元計，此時食物材料成本百分比約：', '["45%", "47%", "48%", "49%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00925', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某飯店之中餐廳4月初食物存貨總值為40萬元，4月食物採購成本200萬元，由自助餐廳移入的 食物成本為20萬元，移出到西餐廳的食物成本為10萬元，4月末的食物存貨總值60萬元，4月 份員工伙食食材費用為20萬元。則4月份的食物成本為何？', '["150萬", "160萬", "170萬", "190萬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00926', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某團膳業者本月銷售產品之收入為1,200,000元，其固定成本為360,000元，食材成本為420,000元， 則食物成本占收入多少的百分比？', '["30%", "35%", "50%", "65%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00927', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '若要以最基本、最安全、最有效率的方法完成工作，勞工應該要做的是：', '["遵循安全作業規範，並依作業程序完成工作", "加強走動式管理，落實績效考核制度", "持續性實施產品教育與訓練", "給予動機之激勵制度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00928', 'dietitian', 'dietitian-moex-111-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關成本之敘述，何者正確？', '["房租屬於變動成本", "食物材料屬於變動成本", "燃料費用屬於固定成本", "乾料費用屬於固定成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "78915ad3adb1", "answer_pdf_sha1": "b45a61057a81", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
